INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('8971f0d3820d90b8', 'OK', '["federal","state","county"]', 'ballot_access', 'What is the primary election system in Oklahoma?', '["Are Oklahoma primaries open or closed?","Do I have to register with a party to vote in the OK primary?","Can unaffiliated voters participate in the Oklahoma primary?"]', 'Oklahoma officially has a closed primary system, meaning voters must be registered with a political party to vote in that party''s primary. However, state law allows recognized political parties to open their primaries to unaffiliated (Independent) voters on a cycle-by-cycle basis. The Democratic Party frequently opts to allow unaffiliated voters to participate, while the Republican primary generally remains closed.', 'https://oklahoma.gov/elections/voter-info/political-party-info.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'All voters and candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('ad48af349c5f5372', 'OK', '["federal","state","county"]', 'runoff_rules', 'Does Oklahoma hold primary runoff elections?', '["What is the threshold to win a primary in OK?","Does Oklahoma require a majority to win a primary?","Oklahoma primary runoff rules"]', 'Yes. Oklahoma requires a candidate to secure an absolute majority (over 50%) of the vote to win a primary election outright. If a primary has three or more candidates and no candidate receives more than 50% of the vote, the top two vote-getters advance to a primary runoff election held later in the summer.', 'https://oklahoma.gov/elections.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'All primary candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('6c9945267de97048', 'OK', '["federal","state","county"]', 'ballot_access', 'Are write-in candidates permitted in Oklahoma?', '["Do write-in votes count in OK?","How to register as a write-in candidate in Oklahoma","Write-in filing deadline Oklahoma"]', 'No. In a major distinctive feature, write-in candidates and write-in voting are explicitly prohibited in Oklahoma for all federal, state, and local elections. If a voter writes a name on the ballot, that vote will not be counted by election officials.', 'https://oksenate.gov/sites/default/files/2019-12/os26.pdf', 'Oklahoma Statutes Title 26 § 7-127', '2026-05-17', 'static', 'statute_citation', 'Write-in candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('d91eb6128255b2c1', 'OK', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for major party candidates in Oklahoma for 2026?', '["When do candidates file for office in Oklahoma?","Oklahoma filing deadline 2026","April filing deadline OK"]', 'Oklahoma has a highly concentrated candidate filing period. Candidates must submit their notarized Declaration of Candidacy (along with a filing fee or petition) during a strict three-day window. For the 2026 election cycle, this filing window occurs from Wednesday, April 1 through Friday, April 3, 2026. Early or late submissions are strictly rejected.', 'https://oklahoma.gov/elections/candidates/2026-candidate-filing-information.html', 'Oklahoma State Election Board - Candidate Filing', '2026-05-17', 'per_cycle', 'official_source_direct', 'Major party candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('6be244dbebaa696d', 'OK', '["federal","state","county"]', 'ballot_access', 'What is the petition signature threshold for independent candidates in Oklahoma?', '["Independent candidate ballot access Oklahoma","Running without a party in OK 2026","How many signatures for independent US Senate OK"]', 'To run as an independent or minor party candidate without paying the standard filing fee, a candidate must submit a petition. The petition must be signed by at least 2% of the registered voters in the specific district, county, or state (depending on the office sought) as of November 1 of the year preceding the election.', 'https://oklahoma.gov/elections/candidates/2026-candidate-filing-information.html', 'Oklahoma State Election Board - Petitions', '2026-05-17', 'static', 'official_source_direct', 'Independent candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('7aebfce9b798053d', 'OK', '["federal","state","county"]', 'ballot_access', 'Does Oklahoma have a sore loser law?', '["Can I run as an independent if I lose the OK primary?","Oklahoma sore loser statute","General election ballot access after primary defeat OK"]', 'Yes. Oklahoma strictly enforces a sore loser law. A candidate who runs unsuccessfully for a political party''s nomination in the primary election is prohibited from subsequently appearing on the general election ballot as an independent candidate for the same office.', 'https://ballotpedia.org/Sore_loser_laws_by_state', 'Ballotpedia - Sore Loser Laws', '2026-05-17', 'static', 'secondary_source', 'Major party candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('e314f581dbc8f575', 'OK', '["state"]', 'ballot_access', 'Do the Governor and Lieutenant Governor run on a joint ticket in Oklahoma?', '["Oklahoma joint ticket rules","How are Lt Gov candidates selected in OK?","Does the Governor pick a running mate in Oklahoma?"]', 'No. In a major accuracy correction to older baselines: while the legislature passed a measure (State Question 798 in 2018) attempting to link the Governor and Lieutenant Governor on a joint ticket starting in 2026, the voters DEFEATED the measure at the ballot box (54% No). Therefore, the Governor and Lieutenant Governor continue to run completely separately in both the primary and general elections.', 'https://ballotpedia.org/Oklahoma_State_Question_798,_Governor_and_Lieutenant_Governor_Joint_Ticket_Amendment_(2018)', 'Ballotpedia - Oklahoma State Question 798', '2026-05-17', 'static', 'secondary_source', 'Statewide executive candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('00a8cbaec8a39149', 'OK', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in Oklahoma for 2026?', '["Oklahoma primary date 2026","When is Election Day 2026 in Oklahoma?","June primary Oklahoma"]', 'The Oklahoma primary election will be held on Tuesday, June 16, 2026. If no candidate secures a majority, the primary runoff election will be held on Tuesday, August 25, 2026. The general election will be held on Tuesday, November 3, 2026. Polls are open from 7:00 a.m. to 7:00 p.m. local time.', 'https://oklahoma.gov/elections/elections-results/2026-election-calendar.html', 'Oklahoma State Election Board - Calendar', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('87407ae2c4b1a771', 'OK', '["state"]', 'election_dates', 'Is the Oklahoma Governor running for election in 2026?', '["Oklahoma Governor election 2026","Who is defending the OK Governor seat?","Is Kevin Stitt term-limited?"]', 'The Oklahoma governorship is an OPEN seat in 2026. Incumbent Governor Kevin Stitt (R) is term-limited and ineligible to seek a third term, as Oklahoma governors are restricted to serving eight total years in office.', 'https://ballotpedia.org/Governor_of_Oklahoma', 'Ballotpedia - Governor of Oklahoma', '2026-05-17', 'static', 'secondary_source', 'Gubernatorial candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('af749298affa4777', 'OK', '["federal"]', 'election_dates', 'Which U.S. Senate seat is up for election in Oklahoma in 2026?', '["Is Markwayne Mullin up for re-election in 2026?","When is James Lankford''s next election?","Oklahoma US Senate cycle 2026"]', 'The Class 2 U.S. Senate seat currently held by Markwayne Mullin (R) is up for election in 2026. Senator James Lankford (Class 3) was re-elected in 2022 and will not appear on the ballot again until 2028.', 'https://www.senate.gov/senators/Class_II.htm', 'U.S. Senate - Class II Senators', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('3f35e004d24072da', 'OK', '["federal"]', 'election_dates', 'How many U.S. House districts are in Oklahoma for the 2026 election?', '["Oklahoma congressional apportionment","Are all OK congressional seats up in 2026?","Number of US Representatives from Oklahoma"]', 'Oklahoma is apportioned 5 U.S. House districts. All five seats are on the 2026 ballot, as U.S. Representatives serve two-year terms.', 'https://oklahoma.gov/elections.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('2f1279aa84afc8e2', 'OK', '["state"]', 'election_dates', 'Which Oklahoma State Legislature seats are up for election in 2026?', '["Are all Oklahoma House seats up in 2026?","Oklahoma Senate election cycle 2026","Which legislative districts are on the ballot in OK?"]', 'All 101 seats in the Oklahoma House of Representatives (2-year terms) are up for election in 2026. The Oklahoma State Senate has 48 members serving 4-year staggered terms; in 2026, half of those seats (the 24 even-numbered districts) are on the ballot.', 'https://oksenate.gov/', 'Oklahoma State Senate', '2026-05-17', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('536efc4f674df2da', 'OK', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Oklahoma in 2026?', '["Is the Attorney General up in 2026?","OK statewide election list 2026","When is the State Auditor election in OK?"]', 'Oklahoma elects almost all of its major statewide executive officers concurrently on a four-year midterm cycle. In 2026, the offices of Governor, Lieutenant Governor, Attorney General, State Auditor and Inspector, State Treasurer, Superintendent of Public Instruction, Commissioner of Labor, Insurance Commissioner, and one seat on the Corporation Commission are all on the ballot.', 'https://oklahoma.gov/elections/candidates/2026-candidate-filing-information.html', 'Oklahoma State Election Board - Candidate Filing', '2026-05-17', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('f12411c80b8d4000', 'OK', '["judicial"]', 'election_dates', 'How are Oklahoma judges selected and are they on the ballot?', '["Oklahoma judicial elections 2026","Are OK judges elected or appointed?","Supreme Court elections Oklahoma"]', 'Oklahoma uses a hybrid system. Justices of the Oklahoma Supreme Court are appointed by the Governor (from a list from the Judicial Nominating Commission) and subsequently face nonpartisan retention elections (''Yes/No'' votes) at the end of their six-year terms. However, local District Court judges are chosen directly by voters in nonpartisan, contested elections.', 'https://www.oscn.net/', 'Oklahoma State Courts Network', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('81a70efb70efbfd1', 'OK', '["state"]', 'election_dates', 'What is the schedule for the Oklahoma State Legislature sessions?', '["When does the OK legislature meet?","Oklahoma legislative session length","Is the Oklahoma legislature full time?"]', 'The Oklahoma State Legislature is a part-time body that meets annually. The regular session convenes on the first Monday in February and is constitutionally mandated to adjourn sine die no later than 5:00 p.m. on the last Friday in May.', 'https://oklegislature.gov/', 'Oklahoma Legislature', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('a3ce218dcaa29c46', 'OK', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of Oklahoma?', '["Age and residency for Oklahoma Governor","Oklahoma Constitution Governor qualifications","Who is eligible to be Governor of OK?"]', 'Under Article VI, Section 3 of the Oklahoma Constitution, a candidate for Governor must be at least 31 years of age, a citizen of the United States, and a qualified elector (resident) of Oklahoma for at least 10 years preceding their election.', 'https://oklahoma.gov/elections/candidates/2026-candidate-filing-information.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'Gubernatorial candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('b8c01d6628bdc3f0', 'OK', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for the Oklahoma State Legislature?', '["Qualifications for OK State Representative","Age requirement Oklahoma State Senate","Do I have to live in my district to run in OK?"]', 'To run for the Oklahoma State Senate, a candidate must be at least 25 years old. To run for the State House, a candidate must be at least 21 years old. Both must be qualified electors and registered voters residing in their respective district for at least six months prior to the filing period.', 'https://oklahoma.gov/elections/candidates/2026-candidate-filing-information.html', 'Oklahoma State Election Board - Qualifications', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('4ec1f50d904a8929', 'OK', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in Oklahoma?', '["US Senate residency requirements Oklahoma","Age to run for Congress in Oklahoma","Federal constitutional requirements for OK candidates"]', 'Federal candidates must meet standard U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be at least 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected.', 'https://oklahoma.gov/elections/candidates/2026-candidate-filing-information.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('2269f3b9c0219651', 'OK', '["state"]', 'candidate_eligibility', 'What are the term limits for the Oklahoma Governor and statewide executives?', '["How many terms can an Oklahoma Governor serve?","Oklahoma executive term limit law","Kevin Stitt term limits OK"]', 'Following State Question 747 in 2010, the Oklahoma Constitution strictly limits the Governor, Lieutenant Governor, and other statewide executive officers to serving no more than 8 total years in any single office throughout their lifetime. (A full two terms).', 'https://ballotpedia.org/Governor_of_Oklahoma', 'Oklahoma Constitution Article VI', '2026-05-17', 'static', 'statute_citation', 'Statewide executive candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('bd16d24a8e5e7550', 'OK', '["state"]', 'candidate_eligibility', 'Does Oklahoma have legislative term limits?', '["How many terms can an Oklahoma state senator serve?","Are there term limits for the Oklahoma House?","Oklahoma legislature term limit status"]', 'Yes. Oklahoma imposes strict cumulative legislative term limits. A state legislator is limited to serving a maximum of 12 CUMULATIVE years total in the Oklahoma Legislature, regardless of whether those years are spent entirely in the House, entirely in the Senate, or split between both chambers.', 'https://oksenate.gov/', 'Oklahoma State Senate - Term Limits', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('e8fda8bb1c55907d', 'OK', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Attorney General in Oklahoma?', '["Qualifications to run for Attorney General in OK","Do I need to be a member of the bar to be OK AG?","Legal requirements for Oklahoma Attorney General"]', 'To run for Attorney General in Oklahoma, a candidate must be at least 31 years of age, a resident of Oklahoma for at least 10 years, and critically, a licensed attorney who is eligible to practice law before the state Supreme Court.', 'https://oklahoma.gov/elections/candidates/2026-candidate-filing-information.html', 'Oklahoma State Election Board - Qualifications', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('9cc82b942cc4dd0b', 'OK', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for county officeholders in Oklahoma?', '["Oklahoma county commissioner qualifications","Can I run for county board in OK?","County residency for OK officials"]', 'To run for a county office (such as County Commissioner, Assessor, or Sheriff), a candidate must generally be a registered voter of the county and a resident of the specific district they seek to represent for at least six months prior to the filing period.', 'https://oklahoma.gov/elections/candidates/2026-candidate-filing-information.html', 'Oklahoma State Election Board - County Candidate Info', '2026-05-17', 'static', 'official_source_direct', 'County candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('68bfc583d22edfa3', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in Oklahoma?', '["Oklahoma voter ID requirements","Do I need my driver''s license to vote in OK?","Acceptable ID for Oklahoma voting"]', 'Yes, but with flexible options. Oklahoma requires voters to present a valid photo ID issued by the federal, state, or tribal government (such as an Oklahoma driver''s license or Passport). However, voters may also use the free non-photo Voter Identification Card mailed to them by the county election board when they registered.', 'https://oklahoma.gov/elections/voter-info/proof-of-identity.html', 'Oklahoma State Election Board - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('213973ead7f0fa55', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'Is Oklahoma a universal mail ballot state, and is no-excuse absentee voting allowed?', '["Do all voters get a mail ballot in Oklahoma?","Oklahoma vote-by-mail system","Do I need an excuse to vote absentee in OK?"]', 'Oklahoma is NOT a universal mail ballot state (ballots are not mailed automatically). However, the state does allow NO-EXCUSE absentee voting. Any registered voter may request an absentee ballot without providing a reason, provided they sign an affidavit that must generally be notarized.', 'https://oklahoma.gov/elections/voter-info/absentee-voting.html', 'Oklahoma State Election Board - Absentee Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('c0360f41b96b1baa', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Oklahoma offer early in-person voting?', '["Can I vote early in person in OK?","Oklahoma early voting dates 2026","When does early voting start in Oklahoma?"]', 'Yes. Oklahoma offers in-person early voting, formally known as ''In-Person Absentee Voting.'' Early voting is generally available on the Wednesday, Thursday, Friday, and Saturday immediately preceding a general election, and on the Thursday, Friday, and Saturday preceding a primary or runoff election.', 'https://oklahoma.gov/elections/voter-info/early-voting.html', 'Oklahoma State Election Board - Early Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('fe1103a723da0a68', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the voter registration deadline and does Oklahoma offer same-day registration?', '["Last day to register to vote in OK","Oklahoma same day voter registration","Voter registration deadline 2026 Oklahoma"]', 'The deadline to register to vote in Oklahoma is 25 days prior to an election. For the November 2026 general election, the deadline is early October. Oklahoma DOES NOT offer same-day voter registration at the polls or during early voting.', 'https://oklahoma.gov/elections/voter-info/register-to-vote.html', 'Oklahoma State Election Board - Voter Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('dbbbc6466c9de6d8', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Oklahoma?', '["How close can I campaign to a polling place in OK?","Oklahoma 300 feet electioneering rule","OK buffer zone around voting centers"]', 'Under Oklahoma state law, electioneering is strictly prohibited within 300 feet of any ballot box while an election is in progress. This applies to both Election Day polling locations and early voting sites, making it one of the largest buffer zones in the nation.', 'https://oklahoma.gov/elections/voter-info/voter-conduct.html', 'Oklahoma State Election Board - Voter Conduct', '2026-05-17', 'static', 'official_source_direct', 'Campaign workers and Voters', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('56bad45ee35aaeb8', 'OK', '["county"]', 'voter_interaction', 'How many counties are in Oklahoma, and who administers elections locally?', '["Oklahoma county election administration","How many county election boards in OK?","Local election control Oklahoma"]', 'Oklahoma is divided into 77 counties. Election administration is handled at the local level by County Election Boards. Statewide campaigns must coordinate heavily with these 77 local boards to manage early voting logistics and absentee ballot processing.', 'https://oklahoma.gov/elections.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('68c1c9fc673cacec', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the Oklahoma voter file?', '["Oklahoma voter database access cost","How to get the voter list in OK","What data is included in the Oklahoma voter file?"]', 'Campaigns and political committees can request the statewide voter registration list from the Oklahoma State Election Board for a prescribed fee. The file contains voter names, addresses, party affiliations, and election history. The data may only be used for election and political purposes.', 'https://oklahoma.gov/elections/voter-info/request-voter-data.html', 'Oklahoma State Election Board - Voter Data', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('1fa536d2b7e575db', 'OK', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in Oklahoma?', '["Where do I file campaign finance reports in OK?","What is the Oklahoma Campaign Reporting System?","Does the OK Election Board handle campaign finance?"]', 'Campaign finance and disclosure laws in Oklahoma are administered and enforced entirely by the Oklahoma Ethics Commission (not the State Election Board). Candidates and committees file their contribution and expenditure reports electronically using The Guardian System.', 'https://www.ok.gov/ethics/', 'Oklahoma Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('9c35caadf47e9c12', 'OK', '["state","county"]', 'finance_ethics', 'What are the individual campaign contribution limits in Oklahoma for the 2026 cycle?', '["Are there contribution limits in Oklahoma?","OK individual donation caps 2026 election","Maximum donation to state legislature Oklahoma"]', 'In Oklahoma, contribution limits apply per election. For the current cycle, an individual may contribute up to $3,500 to a candidate per election (so $3,500 for the primary, $3,500 for the runoff if applicable, and $3,500 for the general election).', 'https://oklahoma.gov/content/dam/ok/en/ethics/documents/campaigns/state-candidates/contribution-chart/2026ElectionContributionChart.pdf', 'Oklahoma Ethics Commission - Contribution Limits', '2026-05-17', 'per_cycle', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('cc049ceb212ac480', 'OK', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions permitted in Oklahoma campaigns?', '["Corporate contribution ban Oklahoma state","Can a business donate to my campaign in OK?","Corporate campaign finance rules Oklahoma"]', 'No. Oklahoma strictly PROHIBITS direct contributions from the general treasury of a corporation or labor union to a candidate''s political campaign committee. Corporate and union funds can only be used to establish and administer a separate PAC.', 'https://oklahoma.gov/content/dam/ok/en/ethics/documents/campaigns/state-candidates/contribution-chart/2026ElectionContributionChart.pdf', 'Oklahoma Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'Candidates and Businesses', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('7956bc89702f25ad', 'OK', '["state","county"]', 'finance_ethics', 'What are the PAC contribution limits to candidates in Oklahoma?', '["OK PAC donation limits to candidates 2026","Political committee vs individual contribution limit Oklahoma","Maximum PAC gift to state legislator OK"]', 'In Oklahoma, a Limited Committee (PAC) may contribute a maximum of $5,000 to a candidate''s committee per election. Like individual limits, this resets for the primary, runoff, and general elections.', 'https://oklahoma.gov/content/dam/ok/en/ethics/documents/campaigns/state-candidates/contribution-chart/2026ElectionContributionChart.pdf', 'Oklahoma Ethics Commission - Contribution Limits', '2026-05-17', 'per_cycle', 'official_source_direct', 'State and County candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('8bbf7195843e2580', 'OK', '["state","county","municipal"]', 'finance_ethics', 'What are Oklahoma''s rapid disclosure requirements for late contributions?', '["Oklahoma 48-hour large contribution report","Late contribution reporting Oklahoma Ethics Commission","When do I file a rapid report in OK?"]', 'Oklahoma mandates rapid disclosure during the critical window before an election. If a candidate committee receives a contribution (or loan) of $1,000 or more in the aggregate from a single source within the two weeks immediately prior to an election, it must be reported to the Ethics Commission within 24 hours.', 'https://www.ok.gov/ethics/', 'Oklahoma Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('234c6b918cf69fb9', 'OK', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for Oklahoma candidates?', '["OK Ethics Commission filing dates 2026","When are campaign finance reports due in OK?","Oklahoma pre-primary and pre-general report deadlines"]', 'Active state-level candidate committees must file comprehensive periodic reports. In an election year, this includes a Pre-Election report due exactly 8 days before each election (primary, runoff, general), and quarterly continuous reports tracking spending in the interim.', 'https://www.ok.gov/ethics/', 'Oklahoma Ethics Commission', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('9217b88872fa2c5d', 'OK', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for Oklahoma legislators?', '["Can Oklahoma legislators raise money during session?","Lobbyist contribution ban OK legislature","Legislative session contribution rules Oklahoma"]', 'Yes. Oklahoma strictly enforces a legislative session freeze. State law and Ethics Rules prohibit members of the legislature (and candidates for legislative office) from intentionally soliciting or accepting campaign contributions from registered lobbyists or lobbyist principals during any regular legislative session and for five days after its adjournment.', 'https://law.justia.com/codes/oklahoma/title-21/section-21-187-1/', 'Oklahoma Statutes Title 21 § 187.1', '2026-05-17', 'static', 'statute_citation', 'State legislative candidates and Lobbyists', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('c9ad06e372f50675', 'OK', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using campaign funds for personal use in Oklahoma?', '["OK personal use prohibition campaign finance","Can I use campaign money for personal items in OK?","Prohibited expenditures Oklahoma Ethics Commission"]', 'Yes. Under Oklahoma Ethics Commission Rules, campaign funds are strictly prohibited from being converted to the personal use of the candidate or any other person. Expenditures must bear a direct relationship to the candidate''s campaign or the execution of their public office.', 'https://www.ok.gov/ethics/', 'Oklahoma Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('116cffac42a7258b', 'OK', '["state"]', 'ballot_access', 'What is the signature threshold for a statutory citizen initiative in Oklahoma?', '["How many signatures to pass a law in Oklahoma?","Oklahoma statutory initiative threshold","Qualifying a ballot measure in OK"]', 'To qualify a statutory initiative for the ballot in Oklahoma, proponents must collect valid signatures equal to at least 8% of the total number of votes cast for the state office receiving the highest number of votes (typically Governor) in the most recent general election.', 'https://oklahoma.gov/elections/voter-info/state-questions.html', 'Oklahoma State Election Board - State Questions', '2026-05-17', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('299ec2ce37f5ae07', 'OK', '["state"]', 'ballot_access', 'What is the signature threshold for a constitutional amendment initiative in Oklahoma?', '["How to amend the Oklahoma Constitution by citizen petition","Oklahoma constitutional amendment signature requirement","Citizen initiative constitutional amendment OK"]', 'To place a citizen-initiated constitutional amendment on the ballot, proponents must gather valid signatures equal to at least 15% of the total number of votes cast for the state office receiving the highest number of votes in the most recent general election.', 'https://oklahoma.gov/elections/voter-info/state-questions.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('f021e3dd64baf0ee', 'OK', '["state"]', 'ballot_access', 'What happens if a citizen initiative is rejected by Oklahoma voters?', '["Can a failed ballot measure be put back on the ballot in OK?","Oklahoma rejected initiative re-petition threshold","Resubmitting a defeated state question Oklahoma"]', 'If an initiative petition is rejected by voters at the polls, it cannot be submitted again for three years, UNLESS proponents manage to gather signatures equal to an exceptionally high threshold of 25% of the votes cast in the last general election.', 'https://ballotpedia.org/Laws_governing_the_initiative_process_in_Oklahoma', 'Ballotpedia - Initiative Process in Oklahoma', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('d517ef0a5ff5d7b5', 'OK', '["state"]', 'ballot_access', 'Who sets the election date for ballot measures and what is the pass threshold in Oklahoma?', '["When do Oklahomans vote on state questions?","Oklahoma ballot measure pass threshold","Does a measure need a supermajority in OK?"]', 'The Governor of Oklahoma has the authority to set the election date for ballot measures (State Questions), deciding whether they will appear on the next general election ballot or be placed on a special election ballot. To become law, a measure requires a simple majority (over 50%) of the total votes cast on that specific question.', 'https://oklahoma.gov/elections/voter-info/state-questions.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('c3373f73c7cf43b6', 'OK', '["federal","state"]', 'redistricting', 'Who draws Oklahoma''s congressional and state legislative maps?', '["Does the OK legislature draw district maps?","Who has the authority to draw district lines in Oklahoma?","Oklahoma redistricting commission"]', 'In Oklahoma, the state legislature holds the primary authority to draw and enact both congressional and state legislative district boundaries. The maps are passed as regular legislation and are subject to the Governor''s signature or veto. If the legislature fails to enact maps on time, a Bipartisan Backup Commission takes over the process.', 'https://ballotpedia.org/Redistricting_in_Oklahoma', 'Ballotpedia - Redistricting in Oklahoma', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('dc48d6289dbb80be', 'OK', '["federal","state"]', 'redistricting', 'What are the legal criteria for redistricting in Oklahoma?', '["Standards for drawing Oklahoma district lines","Oklahoma gerrymandering rules","Map requirements OK"]', 'Under the Oklahoma Constitution and legislative guidelines, districts must be contiguous, compact, and as nearly equal in population as practicable. They must adhere to the federal Voting Rights Act, protect communities of interest, and preserve political subdivisions (like county lines) wherever possible.', 'https://oksenate.gov/redistricting', 'Oklahoma State Senate - Redistricting', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('a9b23ce073a382de', 'OK', '["federal","state"]', 'redistricting', 'Are the current Oklahoma redistricting maps operative for the 2026 cycle?', '["Status of Oklahoma congressional redistricting","Are there pending redistricting lawsuits in Oklahoma?","Oklahoma 2026 legislative boundaries"]', 'Yes. The redistricting maps passed by the legislature and signed into law by Governor Kevin Stitt in late 2021 remain fully operative for the 2026 election cycle. There are no ongoing systemic legal challenges preventing their use.', 'https://oksenate.gov/redistricting', 'Oklahoma State Senate', '2026-05-17', 'static', 'official_source_direct', 'Federal and State legislative candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('28e63c2cd43a44e4', 'OK', '["state"]', 'recall_rules', 'Does Oklahoma have a recall mechanism for state officials?', '["Can the Governor of Oklahoma be recalled?","How to recall a state senator in OK","Statewide recall election rules Oklahoma"]', 'No. The State of Oklahoma does not have any legal or constitutional mechanism permitting the recall of state-level elected officials, including the Governor, statewide executives, or members of the state legislature.', 'https://ballotpedia.org/Laws_governing_recall_in_Oklahoma', 'Laws governing recall in Oklahoma', '2026-05-17', 'static', 'secondary_source', 'Statewide and legislative candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('617e355bba605c5e', 'OK', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in Oklahoma?', '["Oklahoma county commissioner recall rules","Signature requirement local recall Oklahoma","Recalling a mayor in OK"]', 'There is no general, statewide statutory right to recall local officials in Oklahoma. The ability to recall a municipal official is permitted exclusively in municipalities that have established Home Rule charters that explicitly authorize the recall process.', 'https://ballotpedia.org/Laws_governing_recall_in_Oklahoma', 'Laws governing recall in Oklahoma', '2026-05-17', 'static', 'secondary_source', 'Local candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('8417c251ccdd2ba9', 'OK', '["state"]', 'candidate_eligibility', 'Is the Secretary of State an elected office in Oklahoma?', '["Requirements to run for OK Secretary of State","Who can run for Secretary of State in OK?","Oklahoma Secretary of State elections"]', 'No. The Secretary of State in Oklahoma is NOT an elected office. The Secretary is appointed directly by the Governor, with the advice and consent of the State Senate, and serves a four-year term concurrent with the Governor.', 'https://oklahoma.gov/sos/about-us.html', 'Oklahoma Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('29a21ea8000ccebf', 'OK', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for State Treasurer in Oklahoma?', '["Eligibility for Oklahoma State Treasurer","Who can run for Treasurer in OK?","Oklahoma Treasurer residency requirements"]', 'To run for State Treasurer (or other general statewide elected offices), a candidate must be at least 31 years of age, a citizen of the United States, and a qualified elector who has resided in Oklahoma for at least 10 years immediately preceding the election.', 'https://oklahoma.gov/elections/candidates/2026-candidate-filing-information.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('886b286944221947', 'OK', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Lieutenant Governor in Oklahoma?', '["Oklahoma Lt Gov requirements","Does the Lt Gov have the same requirements as the Governor in OK?","Qualifications for Lieutenant Governor of Oklahoma"]', 'Under Article VI, Section 3 of the Oklahoma Constitution, the qualifications for Lieutenant Governor are identical to those for the Governor. A candidate must be at least 31 years of age, a U.S. citizen, and a resident of Oklahoma for at least 10 years preceding their election.', 'https://oklahoma.gov/elections/candidates/2026-candidate-filing-information.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('1183d73b6d87879c', 'OK', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in Oklahoma?', '["Run for school board Oklahoma requirements","Who can be a school board member in OK?","School board residency rules Oklahoma"]', 'To run for a local Board of Education in Oklahoma, a candidate must be a registered voter and must have maintained a primary residence within the boundaries of the school district (and the specific ward/zone, if applicable) for at least six months prior to the filing period.', 'https://oklahoma.gov/elections/candidates/2026-candidate-filing-information.html', 'Oklahoma State Election Board - Local Offices', '2026-05-17', 'static', 'official_source_direct', 'School board candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('debe2b1f4a0505ed', 'OK', '["judicial"]', 'candidate_eligibility', 'What are the qualifications for Oklahoma Supreme Court justices?', '["Oklahoma Supreme Court Justice eligibility","Years of practice required for OK Supreme Court","Are Oklahoma judges elected or appointed?"]', 'To serve on the Oklahoma Supreme Court, a justice must be at least 30 years old, a qualified elector in their respective district for at least one year, and must have been a licensed attorney or judge (or a combination) for at least five years. Justices are appointed by the Governor and subsequently face retention elections.', 'https://www.oscn.net/', 'Oklahoma State Courts Network', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('cc81bd43099d7a20', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee mail-in ballots in Oklahoma?', '["How to fix a rejected signature in OK","Oklahoma ballot cure process deadline","Missing notary on OK mail ballot"]', 'Oklahoma is highly distinctive in that it has NO statutory ballot cure process for absentee ballots. If a voter''s absentee ballot affidavit is missing a signature, missing the required notarization, or fails to meet ID requirements, the ballot is simply rejected by the county election board without providing the voter a post-election window to correct the error.', 'https://oklahoma.gov/elections/voter-info/absentee-voting.html', 'Oklahoma State Election Board - Absentee Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('6003a6fce27d0f49', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Oklahoma?', '["When are military ballots due in Oklahoma?","UOCAVA return deadline OK","Overseas voting rules Oklahoma state"]', 'Under UOCAVA, ballots are transmitted to military and overseas voters at least 45 days before an election. In Oklahoma, voted ballots returned by UOCAVA voters must be received by the County Election Board no later than 7:00 p.m. on Election Day to be counted.', 'https://oklahoma.gov/elections/voter-info/military-and-overseas-voters.html', 'Oklahoma State Election Board - UOCAVA', '2026-05-17', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('4ea80303cb3fe81e', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Oklahoma?', '["What is a provisional ballot in OK?","Voting without ID Oklahoma","When do election workers issue provisional ballots?"]', 'Provisional ballots are issued if a voter cannot produce acceptable photo ID or the voter identification card, or if their name is not found in the precinct registry. The voter must sign a sworn affidavit. The county election board investigates the ballot post-election; there is no secondary window for the voter to bring an ID later.', 'https://oklahoma.gov/elections/voter-info/proof-of-identity.html', 'Oklahoma State Election Board - Provisional Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('dcc4cd67da0d4866', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Oklahoma have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the Oklahoma DPS?","OK motor voter automatic registration","Do I have to register to vote if I get an OK driver''s license?"]', 'No. Oklahoma does NOT have Automatic Voter Registration (AVR). While individuals may register to vote when interacting with the Department of Public Safety (DPS), the process requires the voter to actively opt-in and complete the registration form.', 'https://oklahoma.gov/elections/voter-info/register-to-vote.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('79169ca5092da225', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Oklahoma offer Online Voter Registration?', '["Can I register to vote online in OK?","Oklahoma electronic voter registration","OK Voter Portal online registration"]', 'Yes. Eligible Oklahoma residents with a valid Oklahoma driver''s license or state identification card can securely register to vote or update their registration using the OK Voter Portal. The deadline is 25 days prior to the election.', 'https://okvoterportal.okelections.us/Home/RegWizard', 'Oklahoma State Election Board - OK Voter Portal', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('ff2578cda1295b74', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Oklahoma maintain its voter registration lists?', '["OK voter list maintenance rules","How are inactive voters handled in Oklahoma?","Oklahoma voter roll cleaning process"]', 'Oklahoma conducts regular list maintenance using National Change of Address (NCOA) data and death records. Voters whose mail is returned undeliverable are sent a confirmation notice. If they fail to respond and do not vote in the next two consecutive federal general elections, their registration is canceled.', 'https://oklahoma.gov/elections.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('950bcf4df49701b0', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to return an absentee mail-in ballot in Oklahoma?', '["When is the last day to mail my ballot in OK?","Oklahoma mail ballot postmark deadline","What time are ballots due in Oklahoma?"]', 'Absentee ballots returned by mail must be physically received by the County Election Board no later than 7:00 p.m. on Election Day. If a voter chooses to hand-deliver their standard absentee ballot, it must be delivered by the close of business on the Monday before Election Day and requires proof of identity.', 'https://oklahoma.gov/elections/voter-info/absentee-voting.html', 'Oklahoma State Election Board - Absentee Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('b7ac96d63431120b', 'OK', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in Oklahoma?', '["Does Oklahoma use ranked choice voting?","RCV status in Oklahoma 2026","Instant runoff voting OK"]', 'No. Ranked Choice Voting (RCV) is strictly banned in Oklahoma. In April 2024, Governor Kevin Stitt signed HB 3156 into law, which explicitly prohibits the use of ranked choice voting in all statewide, county, and municipal elections.', 'https://my.lwv.org/oklahoma/voting/ranked-choice-voting', 'League of Women Voters - Oklahoma HB 3156', '2026-05-17', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('9a009453035db907', 'OK', '["federal","state","county"]', 'runoff_rules', 'How are exact ties broken in Oklahoma elections?', '["How are tied elections decided in Oklahoma?","Tie-breaker rules Oklahoma elections","What happens if a race is tied in OK?"]', 'Under current Oklahoma election procedures, if a race remains an exact tie after a recount, the winner is determined by lot (e.g., a random drawing of names) conducted by the appropriate election board. (Note: 2025 legislation, HB1678, proposed requiring a special runoff election for ties, but unless passed and effective, lots are drawn).', 'https://www.okhouse.gov/', 'Oklahoma House of Representatives', '2026-05-17', 'static', 'secondary_source', 'All candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('b568c1c020bcc2f2', 'OK', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on Oklahoma campaign materials?', '["Oklahoma ''Paid for by'' rules","Campaign ad disclaimer requirements OK","Political taglines Oklahoma Ethics Commission"]', 'Oklahoma Ethics Rules require that political advertisements and campaign materials clearly identify the entity that financed the communication. The disclaimer must explicitly state ''Paid for by'' followed by the name of the candidate committee, PAC, or individual authorizing the expenditure.', 'https://www.ok.gov/ethics/', 'Oklahoma Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('bc56ab4794b45d97', 'OK', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Oklahoma?', '["OK campaign coordination rules","When is a PAC expenditure not independent in Oklahoma?","Prohibition on candidate-PAC coordination OK"]', 'An expenditure is no longer considered ''independent'' if it is made in cooperation, consultation, or concert with, or at the request or suggestion of, a candidate or their committee. Once coordinated, the expenditure constitutes an in-kind contribution and is subject to the strict $3,500 per-election individual or $5,000 per-election PAC limits.', 'https://www.ok.gov/ethics/', 'Oklahoma Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('451b9d5725a003fd', 'OK', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in Oklahoma?', '["OK Ethics Commission late fee","Penalty for missing an Oklahoma campaign finance deadline","Ethics Commission fine for late filing OK"]', 'The Oklahoma Ethics Commission has the authority to assess strict administrative fees. Candidates and committees who fail to file required registrations or reports on time face a late filing fee of up to $100 for each day the report is unfiled, up to a maximum penalty of $1,000.', 'https://law.justia.com/codes/oklahoma/title-74/section-74-4256/', 'Oklahoma Statutes Title 74 § 4256', '2026-05-17', 'static', 'statute_citation', 'All candidates and treasurers', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('4558b6a48a0f5298', 'OK', '["state","county","municipal"]', 'finance_ethics', 'When and how must an Oklahoma campaign committee terminate?', '["Closing an Oklahoma campaign committee","Ethics Commission committee termination requirements","Final campaign finance report Oklahoma"]', 'A candidate committee may formally terminate when it achieves a zero cash balance, resolves all outstanding debts or loans, and legally disposes of all surplus funds. A formal ''Final Report'' marking the campaign account as closed must then be filed with the Ethics Commission.', 'https://www.ok.gov/ethics/', 'Oklahoma Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('acd7ddbe1789b009', 'OK', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Oklahoma?', '["OK independent expenditure reporting Ethics Commission","Disclosure for OK independent expenditure groups","Reporting thresholds for outside spending Oklahoma"]', 'Any person or group making independent expenditures exceeding $5,000 must file reports detailing the spending and identifying major contributors. Furthermore, any independent expenditure exceeding $5,000 made during the last two weeks before an election must be reported no later than the next business day.', 'https://www.c4integrity.org/wp-content/uploads/2022/06/Oklahoma-State-Report-FINAL-2022.pdf', 'Oklahoma Ethics Rules / Center for Public Integrity', '2026-05-17', 'static', 'secondary_source', 'Independent groups and PACs', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('8cf213e5c12a50a9', 'OK', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Oklahoma?', '["Oklahoma in-kind contribution valuation rules","Reporting non-monetary donations Oklahoma campaign","Fair market value for in-kind gifts OK"]', 'In-kind contributions (donated goods, services, or equipment not available to the general public) must be reported to the Ethics Commission at their fair market value. Their value counts directly toward the donor''s per-election monetary contribution limit (e.g., $3,500 per election).', 'https://www.ok.gov/ethics/', 'Oklahoma Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('8d6691494bcca05c', 'OK', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in Oklahoma?', '["Oklahoma candidate personal loan limits","Can I pay myself back for a campaign loan in OK?","Reporting candidate loans in Ethics Commission"]', 'No. Candidates may loan or contribute an UNLIMITED amount of their own personal funds to their own campaign committee, as these funds are exempt from standard contribution limits. Loans must be properly documented on disclosures and may be repaid from campaign contributions.', 'https://www.ok.gov/ethics/', 'Oklahoma Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('65ed8ff93e0c23fa', 'OK', '["state","county","municipal"]', 'finance_ethics', 'What can Oklahoma candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in OK?","OK surplus campaign funds rules","Donating remaining campaign funds Oklahoma"]', 'Unexpended campaign funds cannot be converted to personal use. Candidates may retain surplus funds for a future campaign for up to six years, transfer them to a political party, return them to contributors pro-rata, donate them to a charitable organization, or deposit them into the state''s General Revenue Fund.', 'https://www.ok.gov/ethics/', 'Oklahoma Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('b7eda70694643efb', 'OK', '["state","county"]', 'finance_ethics', 'What are the state party contribution limits to candidates in Oklahoma?', '["OK party donation limits to candidates 2026","State party contribution limit Oklahoma","Maximum party gift to state legislator OK"]', 'In Oklahoma, state political party committees have distinct, higher contribution limits than individuals or standard PACs. A state party committee can contribute a maximum of $25,000 to a gubernatorial candidate per campaign, and up to $10,000 to a state legislative candidate per campaign.', 'https://oklahoma.gov/content/dam/ok/en/ethics/documents/campaigns/state-candidates/contribution-chart/2026ElectionContributionChart.pdf', 'Oklahoma Ethics Commission - Contribution Limits', '2026-05-17', 'per_cycle', 'official_source_direct', 'State and County candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('72c2d00bcfd64dfa', 'OK', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in Oklahoma?', '["Can felons vote in Oklahoma state?","Felony voting rights restoration OK","Voting on parole in Oklahoma"]', 'In Oklahoma, individuals convicted of a felony lose their right to vote while serving their sentence. Following recent legislative updates (HB 1629/2024), voting rights are automatically restored immediately upon the completion of all court-mandated calendar days of the sentence, including all periods of incarceration, probation, and parole.', 'https://ccresourcecenter.org/state-restoration-profiles/oklahoma-restoration-of-rights-pardon-expungement-sealing/', 'Oklahoma Statutes Title 26 § 4-101', '2026-05-17', 'static', 'statute_citation', 'Voters', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('b7895c90002ff558', 'OK', '["county"]', 'election_dates', 'What are the terms and election cycles for county offices in Oklahoma?', '["When are county sheriffs elected in OK?","Oklahoma county official term lengths","Are county commissioners on the 2026 ballot?"]', 'Elected county officials in Oklahoma—including County Commissioners, Sheriffs, Assessors, and Treasurers—serve four-year terms. They are elected on alternating, staggered cycles during even-numbered years, so many key county executive offices will be featured on the 2026 midterm ballot.', 'https://oklahoma.gov/elections/candidates/2026-candidate-filing-information.html', 'Oklahoma State Election Board', '2026-05-17', 'per_cycle', 'official_source_direct', 'County candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('869acb424d6100f5', 'OK', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for Oklahoma elections?', '["When are Oklahoma election results official?","OK certification deadline","State Election Board meeting Oklahoma"]', 'County Election Boards must certify their local election results by 5:00 p.m. on the Friday immediately following the election. The Oklahoma State Election Board then meets to officially certify statewide and federal election returns on the Tuesday following the election (one week after Election Day).', 'https://oklahoma.gov/elections.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'All candidates and campaigns', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('e37b19442fca5fb9', 'OK', '["federal","state"]', 'election_dates', 'When and how are special elections called in Oklahoma?', '["Oklahoma special election timeline","Who calls a special election to fill a US House vacancy in OK?","Filling a midterm vacancy Oklahoma"]', 'Special elections to fill a vacancy in a federal office (like the U.S. House) or the state legislature are called by a writ of election issued by the Governor. The Governor has the authority to set the dates for the special primary and general elections to fill the unexpired term.', 'https://oklahoma.gov/elections.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('bdc09f90018d34a3', 'OK', '["judicial"]', 'election_dates', 'What is the election cycle for Oklahoma Supreme Court justices?', '["When do OK Supreme Court justices run?","Oklahoma judicial retention elections","Terms for Oklahoma Supreme Court"]', 'After being appointed by the Governor, a newly appointed Supreme Court justice must face a retention election (''Yes'' or ''No'' vote) during the first general election that occurs more than one year after their appointment. If retained by voters, they serve a full six-year term before facing another retention election.', 'https://www.oscn.net/', 'Oklahoma State Courts Network', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1'),
  ('95982c7d196f406a', 'OK', '["federal","state","county"]', 'runoff_rules', 'Does Oklahoma hold general election runoffs if no candidate reaches a certain threshold?', '["Are there runoffs in Oklahoma general elections?","Oklahoma majority vote requirement general election","What happens if no one gets 50% in OK?"]', 'No. While Oklahoma requires a 50%+1 absolute majority to win a primary election (triggering a runoff if unmet), the general election does NOT require a majority. In the November general election, the candidate who receives a simple plurality (the most votes) is declared the winner.', 'https://oklahoma.gov/elections.html', 'Oklahoma State Election Board', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-51-00_oklahoma_full_v1')
